    <div class="toggle-group">
        <div class="toggle-item">
            <label class="toggle-label">
                <span>Email Notifications</span>
                <input type="checkbox" class="form-check-input toggle-switch" checked="@EmailNotifications"
                       @onchange="e => EmailNotifications = (bool)(e.Value ?? false)" />
            </label>
        </div>

        <div class="toggle-item">
            <label class="toggle-label">
                <span>Push Notifications</span>
                <input type="checkbox" class="form-check-input toggle-switch" checked="@PushNotifications"
                       @onchange="e => PushNotifications = (bool)(e.Value ?? false)" />
            </label>
        </div>

        <div class="toggle-item">
            <label class="toggle-label">
                <span>Weekly Digest</span>
                <input type="checkbox" class="form-check-input toggle-switch" checked="@WeeklyDigest"
                       @onchange="e => WeeklyDigest = (bool)(e.Value ?? false)" />
            </label>
        </div>
    </div>

    <h4 class="mt-4">Muted Channels</h4>
    <div class="channel-list">
        @foreach (var channel in AllChannels)
        {
            var isMuted = MutedChannels.Contains(channel);
            <div class="channel-item">
                <label class="form-check-label">
                    <input type="checkbox" class="form-check-input" checked="@isMuted"
                           @onchange="e => ToggleChannel(channel, (bool)(e.Value ?? false))" />
                    <span>#@channel</span>
                </label>
            </div>
        }
    </div>

    <div class="button-group">
        <button class="btn btn-primary" @onclick="SaveAsync">Save Preferences</button>
    </div>
</div>

@code {
    [Parameter] public NotificationPrefs? Prefs { get; set; }
    [Parameter] public EventCallback<NotificationPrefs> OnSave { get; set; }

    private bool EmailNotifications;
    private bool PushNotifications;
    private bool WeeklyDigest;
    private List<string> MutedChannels = [];

    private static readonly string[] AllChannels = ["general", "announcements", "random", "engineering", "design", "marketing"];

    private NotificationPrefs? _lastPrefs;

    protected override void OnParametersSet()
    {
        if (Prefs is not null && _lastPrefs != Prefs)
        {
            _lastPrefs = Prefs;
            EmailNotifications = Prefs.EmailNotifications;
            PushNotifications = Prefs.PushNotifications;
            WeeklyDigest = Prefs.WeeklyDigest;
            MutedChannels = [.. Prefs.MutedChannels];
        }
    }

    private void ToggleChannel(string channel, bool muted)
    {
        if (muted && !MutedChannels.Contains(channel))
            MutedChannels.Add(channel);
        else if (!muted)
            MutedChannels.Remove(channel);
    }

    private async Task SaveAsync()
    {
        var updated = new NotificationPrefs(EmailNotifications, PushNotifications, WeeklyDigest, [.. MutedChannels]);
        await OnSave.InvokeAsync(updated);
        _lastPrefs = updated;
    }
}

@using sv_8cbf60a433d84ae6be97c1cb1bc3d014.Models

<div class="settings-section">
    <h3>Security Settings</h3>

    <ChangePasswordPanel OnPasswordChange="OnPasswordChange" />

    <div class="toggle-item mt-4">
        <label class="toggle-label">
            <span>
                Two-Factor Authentication
                @if (Security?.TwoFactorEnabled == true)
                {
                    <span class="badge bg-success ms-2">Enabled</span>
                }
                else
                {
                    <span class="badge bg-secondary ms-2">Disabled</span>
                }
            </span>
            <input type="checkbox" class="form-check-input toggle-switch"
                   checked="@(Security?.TwoFactorEnabled ?? false)"
                   @onchange="OnToggle2FA" />
        </label>
    </div>

    @if (Security?.LastPasswordChange is not null)
    {
        <p class="text-muted mt-2">Last password change: @Security.LastPasswordChange.Value.ToString("MMMM dd, yyyy")</p>
    }

    <h4 class="mt-4">Active Sessions</h4>
    <div class="table-responsive">
        <table class="table table-striped">
            <thead>
                <tr>
                    <th>Device</th>
                    <th>Location</th>
                    <th>Last Active</th>
                    <th></th>
                </tr>
            </thead>
            <tbody>
                @if (Security?.Sessions is not null)
                {
                    @foreach (var session in Security.Sessions)
                    {
                        var isCurrentSession = session == Security.Sessions.FirstOrDefault();
                        <tr>
                            <td>@session.Device</td>
                            <td>@session.Location</td>
                            <td>@FormatLastActive(session.LastActive)</td>
                            <td>
                                @if (isCurrentSession)
                                {
                                    <span class="badge bg-info">Current</span>
                                }
                                else
                                {
                                    <button class="btn btn-sm btn-outline-danger"
                                            @onclick="() => ShowRevokeDialog(session)">
                                        Revoke
                                    </button>
                                }
                            </td>
                        </tr>
                    }
                }
            </tbody>
        </table>
    </div>

    @if (_sessionToRevoke is not null)
    {
        <RevokeSessionDialog Device="@_sessionToRevoke.Device"
                             Location="@_sessionToRevoke.Location"
                             OnConfirm="ConfirmRevokeAsync"
                             OnCancel="CancelRevoke" />
    }
</div>

@code {
    [Parameter] public SecuritySettings? Security { get; set; }
    [Parameter] public EventCallback<(string Current, string New)> OnPasswordChange { get; set; }
    [Parameter] public EventCallback<bool> OnToggle2FA { get; set; }
    [Parameter] public EventCallback<string> OnRevokeSession { get; set; }

    private ActiveSession? _sessionToRevoke;

    private void ShowRevokeDialog(ActiveSession session) => _sessionToRevoke = session;
    private void CancelRevoke() => _sessionToRevoke = null;

    private async Task ConfirmRevokeAsync()
    {
        if (_sessionToRevoke is not null)
        {
            await OnRevokeSession.InvokeAsync(_sessionToRevoke.Id);
            _sessionToRevoke = null;
        }
    }

    private static string FormatLastActive(DateTime lastActive)
    {
        var diff = DateTime.UtcNow - lastActive;
        if (diff.TotalMinutes < 1) return "Just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes}m ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }
}

@using sv_8cbf60a433d84ae6be97c1cb1bc3d014.Models

<div class="settings-section">
    <h3>Appearance</h3>

    <div class="form-group">
        <label class="fw-bold">Theme</label>
        <div class="radio-group">
            @foreach (var theme in new[] { "Light", "Dark", "System" })
            {
                <label class="radio-option">
                    <input type="radio" name="theme" value="@theme"
                           checked="@(Theme == theme)"
                           @onchange="() => Theme = theme" />
                    <span>@theme</span>
                </label>
            }
        </div>
    </div>

    <div class="form-group">
        <label class="fw-bold">Font Size</label>
        <div class="radio-group">
            @foreach (var size in new[] { "Small", "Medium", "Large" })
            {
                <label class="radio-option">
                    <input type="radio" name="fontSize" value="@size"
                           checked="@(FontSize == size)"
                           @onchange="() => FontSize = size" />
                    <span>@size</span>
                </label>
            }
        </div>
    </div>

    <div class="form-group">
        <label class="fw-bold">Language</label>
        <select class="form-select" value="@Language" @onchange="e => Language = e.Value?.ToString() ?? string.Empty">
            @foreach (var lang in Languages)
            {
                <option value="@lang">@lang</option>
            }
        </select>
    </div>

    <div class="toggle-item">
        <label class="toggle-label">
            <span class="fw-bold">Compact Mode</span>
            <input type="checkbox" class="form-check-input toggle-switch"
                   checked="@CompactMode"
                   @onchange="e => CompactMode = (bool)(e.Value ?? false)" />
        </label>
    </div>

    <h4 class="mt-4">Preview</h4>
    <div class="appearance-preview @PreviewThemeClass" style="font-size: @PreviewFontSize;">
        <div class="preview-header">Sample Header</div>
        <p class="preview-text">
            This is a preview of how your content will look with the selected appearance settings.
        </p>
        <div class="preview-items @(CompactMode ? "compact" : "")">
            <div class="preview-item">📧 Inbox <span class="badge bg-primary">3</span></div>
            <div class="preview-item">📁 Documents</div>
            <div class="preview-item">⚙️ Settings</div>
        </div>
    </div>

    <div class="button-group">
        <button class="btn btn-primary" @onclick="SaveAsync">Save</button>
    </div>
</div>

@code {
    [Parameter] public AppearanceSettings? Settings { get; set; }
    [Parameter] public EventCallback<AppearanceSettings> OnSave { get; set; }

    private string Theme = "Light";
    private string FontSize = "Medium";
    private string Language = "English";
    private bool CompactMode;

    private static readonly string[] Languages = ["English", "Spanish", "French", "German", "Japanese", "Chinese", "Portuguese"];

    private AppearanceSettings? _lastSettings;

    protected override void OnParametersSet()
    {
        if (Settings is not null && _lastSettings != Settings)
        {
            _lastSettings = Settings;
            Theme = Settings.Theme;
            FontSize = Settings.FontSize;
            Language = Settings.Language;
            CompactMode = Settings.CompactMode;
        }
    }

    private string PreviewThemeClass => Theme switch
    {
        "Dark" => "preview-dark",
        "System" => "preview-system",
        _ => "preview-light"
    };

    private string PreviewFontSize => FontSize switch
    {
        "Small" => "0.85rem",
        "Large" => "1.15rem",
        _ => "1rem"
    };

    private async Task SaveAsync()
    {
        var updated = new AppearanceSettings(Theme, FontSize, Language, CompactMode);
        await OnSave.InvokeAsync(updated);
        _lastSettings = updated;
    }
}

