@code {
    [Parameter] public UserProfile? Profile { get; set; }
    [Parameter] public EventCallback<UserProfile> OnSave { get; set; }

    private string DisplayName = string.Empty;
    private string Email = string.Empty;
    private string AvatarUrl = string.Empty;
    private string Bio = string.Empty;
    private string? SuccessMessage;

    protected override void OnParametersSet()
    {
        if (Profile is not null && string.IsNullOrEmpty(DisplayName) && _lastProfile != Profile)
        {
            LoadFromProfile(Profile);
        }
    }

    private UserProfile? _lastProfile;

    private void LoadFromProfile(UserProfile profile)
    {
        _lastProfile = profile;
        DisplayName = profile.DisplayName;
        Email = profile.Email;
        AvatarUrl = profile.AvatarUrl;
        Bio = profile.Bio;
    }

    private async Task SaveAsync()
    {
        var updated = new UserProfile(DisplayName, Email, AvatarUrl, Bio);
        await OnSave.InvokeAsync(updated);
        _lastProfile = updated;
        SuccessMessage = "Profile saved successfully!";
        StateHasChanged();
        _ = ClearMessageAfterDelay();
    }

    private void Discard()
    {
        if (Profile is not null)
        {
            LoadFromProfile(Profile);
        }
        SuccessMessage = null;
    }

    private async Task ClearMessageAfterDelay()
    {
        await Task.Delay(3000);
        SuccessMessage = null;
        await InvokeAsync(StateHasChanged);
    }
}
