                <label>New Password</label>
                <input type="password" class="form-control" @bind="NewPassword" />
            </div>
            <div class="form-group">
                <label>Confirm New Password</label>
                <input type="password" class="form-control" @bind="ConfirmPassword" />
            </div>

            @if (!string.IsNullOrEmpty(ErrorMessage))
            {
                <div class="alert alert-danger">@ErrorMessage</div>
            }
            @if (!string.IsNullOrEmpty(SuccessMessage))
            {
                <div class="alert alert-success">@SuccessMessage</div>
            }

            <button class="btn btn-warning" @onclick="UpdatePasswordAsync" disabled="@IsSubmitting">
                @(IsSubmitting ? "Updating..." : "Update Password")
            </button>
        </div>
    }
</div>

@code {
    [Parameter] public EventCallback<(string Current, string New)> OnPasswordChange { get; set; }

    private bool IsExpanded;
    private string CurrentPassword = string.Empty;
    private string NewPassword = string.Empty;
    private string ConfirmPassword = string.Empty;
    private string? ErrorMessage;
    private string? SuccessMessage;
    private bool IsSubmitting;

    private async Task UpdatePasswordAsync()
    {
        ErrorMessage = null;
        SuccessMessage = null;

        if (string.IsNullOrWhiteSpace(CurrentPassword) || string.IsNullOrWhiteSpace(NewPassword))
        {
            ErrorMessage = "All password fields are required.";
            return;
        }

        if (NewPassword != ConfirmPassword)
        {
            ErrorMessage = "New password and confirmation do not match.";
            return;
        }

        if (NewPassword.Length < 8)
        {
            ErrorMessage = "New password must be at least 8 characters.";
            return;
        }

        IsSubmitting = true;
        try
        {
            await OnPasswordChange.InvokeAsync((CurrentPassword, NewPassword));
            SuccessMessage = "Password updated successfully!";
            CurrentPassword = string.Empty;
            NewPassword = string.Empty;
            ConfirmPassword = string.Empty;
        }
        catch (Exception ex)
        {
            ErrorMessage = $"Failed to update password: {ex.Message}";
        }
        finally
        {
            IsSubmitting = false;
        }
    }
}
