@using sv_8cbf60a433d84ae6be97c1cb1bc3d014.Models

<nav class="settings-sidebar">
    <h5 class="sidebar-title">Settings</h5>
    <ul class="sidebar-nav">
        @foreach (var section in Sections)
        {
            <li class="sidebar-nav-item @(section.Key == ActiveSection ? "active" : "")"
                @onclick="() => OnSectionChanged.InvokeAsync(section.Key)">
                <span class="sidebar-icon">@section.Icon</span>
                <span>@section.Label</span>
            </li>
        }
    </ul>
</nav>

@code {
    [Parameter] public string ActiveSection { get; set; } = "Profile";
    [Parameter] public EventCallback<string> OnSectionChanged { get; set; }

    private record SectionInfo(string Key, string Label, string Icon);

    private static readonly SectionInfo[] Sections =
    [
        new("Profile", "Profile", "👤"),
        new("Notifications", "Notifications", "🔔"),
        new("Security", "Security", "🔒"),
        new("Appearance", "Appearance", "🎨"),
    ];
}

@using sv_8cbf60a433d84ae6be97c1cb1bc3d014.Models

<div class="settings-section">
    <h3>Profile Settings</h3>

    <div class="avatar-preview">
        <img src="@AvatarUrl" alt="Avatar" class="avatar-img" />
        <div class="avatar-url-display">
            <label>Avatar URL</label>
            <input type="text" class="form-control" value="@AvatarUrl" @oninput="e => AvatarUrl = e.Value?.ToString() ?? string.Empty" />
        </div>
    </div>

    <div class="form-group">
        <label>Display Name</label>
        <input type="text" class="form-control" @bind="DisplayName" />
    </div>

    <div class="form-group">
        <label>Email</label>
        <input type="email" class="form-control" @bind="Email" />
    </div>

    <div class="form-group">
        <label>Bio</label>
        <textarea class="form-control" rows="4" @bind="Bio"></textarea>
    </div>

    @if (!string.IsNullOrEmpty(SuccessMessage))
    {
        <div class="alert alert-success toast-message">@SuccessMessage</div>
    }

    <div class="button-group">
        <button class="btn btn-primary" @onclick="SaveAsync">Save Changes</button>
        <button class="btn btn-outline-secondary" @onclick="Discard">Discard Changes</button>
    </div>
</div>

@code {
    [Parameter] public UserProfile? Profile { get; set; }
    [Parameter] public EventCallback<UserProfile> OnSave { get; set; }

    private string DisplayName = string.Empty;
    private string Email = string.Empty;
    private string AvatarUrl = string.Empty;
    private string Bio = string.Empty;
    private string? SuccessMessage;

    protected override void OnParametersSet()
    {
        if (Profile is not null && string.IsNullOrEmpty(DisplayName) && _lastProfile != Profile)
        {
            LoadFromProfile(Profile);
        }
    }

    private UserProfile? _lastProfile;

    private void LoadFromProfile(UserProfile profile)
    {
        _lastProfile = profile;
        DisplayName = profile.DisplayName;
        Email = profile.Email;
        AvatarUrl = profile.AvatarUrl;
        Bio = profile.Bio;
    }

    private async Task SaveAsync()
    {
        var updated = new UserProfile(DisplayName, Email, AvatarUrl, Bio);
        await OnSave.InvokeAsync(updated);
        _lastProfile = updated;
        SuccessMessage = "Profile saved successfully!";
        StateHasChanged();
        _ = ClearMessageAfterDelay();
    }

    private void Discard()
    {
        if (Profile is not null)
        {
            LoadFromProfile(Profile);
        }
        SuccessMessage = null;
    }

    private async Task ClearMessageAfterDelay()
    {
        await Task.Delay(3000);
        SuccessMessage = null;
        await InvokeAsync(StateHasChanged);
    }
}

