@using sv_8cbf60a433d84ae6be97c1cb1bc3d014.Models

<div class="settings-section">
    <h3>Notification Preferences</h3>

    <div class="toggle-group">
        <div class="toggle-item">
            <label class="toggle-label">
                <span>Email Notifications</span>
                <input type="checkbox" class="form-check-input toggle-switch" checked="@EmailNotifications"
                       @onchange="e => EmailNotifications = (bool)(e.Value ?? false)" />
            </label>
        </div>

        <div class="toggle-item">
            <label class="toggle-label">
                <span>Push Notifications</span>
                <input type="checkbox" class="form-check-input toggle-switch" checked="@PushNotifications"
                       @onchange="e => PushNotifications = (bool)(e.Value ?? false)" />
            </label>
        </div>

        <div class="toggle-item">
            <label class="toggle-label">
                <span>Weekly Digest</span>
                <input type="checkbox" class="form-check-input toggle-switch" checked="@WeeklyDigest"
                       @onchange="e => WeeklyDigest = (bool)(e.Value ?? false)" />
            </label>
        </div>
    </div>

    <h4 class="mt-4">Muted Channels</h4>
    <div class="channel-list">
        @foreach (var channel in AllChannels)
        {
            var isMuted = MutedChannels.Contains(channel);
            <div class="channel-item">
                <label class="form-check-label">
                    <input type="checkbox" class="form-check-input" checked="@isMuted"
                           @onchange="e => ToggleChannel(channel, (bool)(e.Value ?? false))" />
                    <span>#@channel</span>
                </label>
            </div>
        }
    </div>

    <div class="button-group">
        <button class="btn btn-primary" @onclick="SaveAsync">Save Preferences</button>
    </div>
</div>

@code {
    [Parameter] public NotificationPrefs? Prefs { get; set; }
    [Parameter] public EventCallback<NotificationPrefs> OnSave { get; set; }

    private bool EmailNotifications;
    private bool PushNotifications;
    private bool WeeklyDigest;
    private List<string> MutedChannels = [];

    private static readonly string[] AllChannels = ["general", "announcements", "random", "engineering", "design", "marketing"];

    private NotificationPrefs? _lastPrefs;

    protected override void OnParametersSet()
    {
        if (Prefs is not null && _lastPrefs != Prefs)
        {
            _lastPrefs = Prefs;
            EmailNotifications = Prefs.EmailNotifications;
            PushNotifications = Prefs.PushNotifications;
            WeeklyDigest = Prefs.WeeklyDigest;
            MutedChannels = [.. Prefs.MutedChannels];
        }
    }

    private void ToggleChannel(string channel, bool muted)
    {
        if (muted && !MutedChannels.Contains(channel))
            MutedChannels.Add(channel);
        else if (!muted)
            MutedChannels.Remove(channel);
    }

    private async Task SaveAsync()
    {
        var updated = new NotificationPrefs(EmailNotifications, PushNotifications, WeeklyDigest, [.. MutedChannels]);
        await OnSave.InvokeAsync(updated);
        _lastPrefs = updated;
    }
}

