@using sv_8cbf60a433d84ae6be97c1cb1bc3d014.Models

<div class="settings-section">
    <h3>Security Settings</h3>

    <ChangePasswordPanel OnPasswordChange="OnPasswordChange" />

    <div class="toggle-item mt-4">
        <label class="toggle-label">
            <span>
                Two-Factor Authentication
                @if (Security?.TwoFactorEnabled == true)
                {
                    <span class="badge bg-success ms-2">Enabled</span>
                }
                else
                {
                    <span class="badge bg-secondary ms-2">Disabled</span>
                }
            </span>
            <input type="checkbox" class="form-check-input toggle-switch"
                   checked="@(Security?.TwoFactorEnabled ?? false)"
                   @onchange="OnToggle2FA" />
        </label>
    </div>

    @if (Security?.LastPasswordChange is not null)
    {
        <p class="text-muted mt-2">Last password change: @Security.LastPasswordChange.Value.ToString("MMMM dd, yyyy")</p>
    }

    <h4 class="mt-4">Active Sessions</h4>
    <div class="table-responsive">
        <table class="table table-striped">
            <thead>
                <tr>
                    <th>Device</th>
                    <th>Location</th>
                    <th>Last Active</th>
                    <th></th>
                </tr>
            </thead>
            <tbody>
                @if (Security?.Sessions is not null)
                {
                    @foreach (var session in Security.Sessions)
                    {
                        var isCurrentSession = session == Security.Sessions.FirstOrDefault();
                        <tr>
                            <td>@session.Device</td>
                            <td>@session.Location</td>
                            <td>@FormatLastActive(session.LastActive)</td>
                            <td>
                                @if (isCurrentSession)
                                {
                                    <span class="badge bg-info">Current</span>
                                }
                                else
                                {
                                    <button class="btn btn-sm btn-outline-danger"
                                            @onclick="() => ShowRevokeDialog(session)">
                                        Revoke
                                    </button>
                                }
                            </td>
                        </tr>
                    }
                }
            </tbody>
        </table>
    </div>

    @if (_sessionToRevoke is not null)
    {
        <RevokeSessionDialog Device="@_sessionToRevoke.Device"
                             Location="@_sessionToRevoke.Location"
                             OnConfirm="ConfirmRevokeAsync"
                             OnCancel="CancelRevoke" />
    }
</div>

@code {
    [Parameter] public SecuritySettings? Security { get; set; }
    [Parameter] public EventCallback<(string Current, string New)> OnPasswordChange { get; set; }
    [Parameter] public EventCallback<bool> OnToggle2FA { get; set; }
    [Parameter] public EventCallback<string> OnRevokeSession { get; set; }

    private ActiveSession? _sessionToRevoke;

    private void ShowRevokeDialog(ActiveSession session) => _sessionToRevoke = session;
    private void CancelRevoke() => _sessionToRevoke = null;

    private async Task ConfirmRevokeAsync()
    {
        if (_sessionToRevoke is not null)
        {
            await OnRevokeSession.InvokeAsync(_sessionToRevoke.Id);
            _sessionToRevoke = null;
        }
    }

    private static string FormatLastActive(DateTime lastActive)
    {
        var diff = DateTime.UtcNow - lastActive;
        if (diff.TotalMinutes < 1) return "Just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes}m ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }
}

