toolArgs.file_text:
/* ===== Settings Dashboard Layout ===== */
.settings-dashboard {
    display: flex;
    min-height: 80vh;
    border: 1px solid #dee2e6;
    border-radius: 8px;
    overflow: hidden;
    background: #fff;
}

/* ===== Sidebar ===== */
.settings-sidebar {
    width: 220px;
    background: #f8f9fa;
    border-right: 1px solid #dee2e6;
    flex-shrink: 0;
}

.sidebar-title {
    padding: 1.25rem 1rem 0.75rem;
    margin: 0;
    font-weight: 600;
    color: #495057;
    font-size: 0.85rem;
    text-transform: uppercase;
    letter-spacing: 0.05em;
}

.sidebar-nav {
    list-style: none;
    padding: 0;
    margin: 0;
}

.sidebar-nav-item {
    padding: 0.75rem 1rem;
    cursor: pointer;
    display: flex;
    align-items: center;
    gap: 0.5rem;
    color: #495057;
    transition: background-color 0.15s, color 0.15s;
    border-left: 3px solid transparent;
}

.sidebar-nav-item:hover {
    background: #e9ecef;
}

.sidebar-nav-item.active {
    background: #fff;
    color: #0d6efd;
    border-left-color: #0d6efd;
    font-weight: 600;
}

.sidebar-icon {
    font-size: 1.1rem;
}

/* ===== Content Area ===== */
.settings-content {
    flex: 1;
    padding: 2rem;
    overflow-y: auto;
}

.settings-section h3 {
    margin-bottom: 1.5rem;
    font-weight: 600;
    color: #212529;
}

.settings-section h4 {
    font-size: 1.1rem;
    font-weight: 600;
    color: #495057;
}

/* ===== Form Groups ===== */
.form-group {
    margin-bottom: 1rem;
}

.form-group label {
    display: block;
    margin-bottom: 0.35rem;
    font-weight: 500;
    color: #495057;
}

/* ===== Buttons ===== */
.button-group {
    margin-top: 1.5rem;
    display: flex;
    gap: 0.75rem;
}

/* ===== Toast ===== */
.toast-message {
    margin-top: 1rem;
    animation: fadeIn 0.3s ease-in;
}

@keyframes fadeIn {
    from { opacity: 0; transform: translateY(-8px); }
    to { opacity: 1; transform: translateY(0); }
}

/* ===== Avatar Preview ===== */
.avatar-preview {
    display: flex;
    align-items: center;
    gap: 1.25rem;
    margin-bottom: 1.5rem;
    padding: 1rem;
    background: #f8f9fa;
    border-radius: 8px;
}

.avatar-img {
    width: 80px;
    height: 80px;
    border-radius: 50%;
    object-fit: cover;
    border: 3px solid #dee2e6;
}

.avatar-url-display {
    flex: 1;
}

.avatar-url-display label {
    display: block;
    font-weight: 500;
    margin-bottom: 0.25rem;
    color: #495057;
}

/* ===== Toggle Switches ===== */
.toggle-group {
    display: flex;
    flex-direction: column;
    gap: 0.25rem;
}

.toggle-item {
    padding: 0.5rem 0;
}

.toggle-label {
    display: flex;
    justify-content: space-between;
    align-items: center;
    cursor: pointer;
    font-weight: 500;
}

.toggle-switch {
    width: 2.5em !important;
    height: 1.25em !important;
    cursor: pointer;
}

/* ===== Channel List ===== */
.channel-list {
    display: flex;
    flex-direction: column;
    gap: 0.4rem;
    padding: 0.5rem 0;
}

.channel-item label {
    display: flex;
    align-items: center;
    gap: 0.5rem;
    cursor: pointer;
}

/* ===== Change Password Panel ===== */
.change-password-panel {
    border: 1px solid #dee2e6;
    border-radius: 6px;
    overflow: hidden;
}

.panel-toggle {
    width: 100%;
    text-align: left;
    padding: 0.75rem 1rem;
    text-decoration: none;
    font-weight: 600;
    color: #495057;
    font-size: 1rem;
}

.panel-toggle:hover {
    background: #f8f9fa;
}

.expand-icon {
    margin-right: 0.5rem;
}

.panel-body {
    padding: 1rem;
    border-top: 1px solid #dee2e6;
    background: #fafbfc;
}

.panel-body .form-group {
    max-width: 400px;
}

/* ===== Revoke Session Modal ===== */
.modal-backdrop {
    position: fixed;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    background: rgba(0, 0, 0, 0.5);
    display: flex;
    align-items: center;
    justify-content: center;
    z-index: 1050;
}

.modal-dialog {
    background: #fff;
    border-radius: 8px;
    width: 100%;
    max-width: 440px;
    box-shadow: 0 8px 32px rgba(0, 0, 0, 0.15);
}

.modal-header {
    padding: 1rem 1.25rem;
    border-bottom: 1px solid #dee2e6;
}

.modal-header h5 {
    margin: 0;
    font-weight: 600;
}

.modal-body {
    padding: 1.25rem;
}

.modal-footer {
    padding: 0.75rem 1.25rem;
    border-top: 1px solid #dee2e6;
    display: flex;
    justify-content: flex-end;
    gap: 0.5rem;
}

/* ===== Radio Groups ===== */
.radio-group {
    display: flex;
    gap: 1.25rem;
    padding: 0.25rem 0;
}

.radio-option {
    display: flex;
    align-items: center;
    gap: 0.35rem;
    cursor: pointer;
}

/* ===== Appearance Preview ===== */
.appearance-preview {
    border: 1px solid #dee2e6;
    border-radius: 8px;
    padding: 1.25rem;
    transition: all 0.3s ease;
}

.preview-light {
    background: #ffffff;
    color: #212529;
}

.preview-dark {
    background: #1e1e2e;
    color: #cdd6f4;
    border-color: #45475a;
}

.preview-system {
    background: linear-gradient(135deg, #ffffff 50%, #1e1e2e 50%);
    color: #495057;
}

.preview-header {
    font-weight: 700;
    font-size: 1.15em;
    margin-bottom: 0.5rem;
}

.preview-text {
    margin-bottom: 0.75rem;
    opacity: 0.85;
}

.preview-items {
    display: flex;
    flex-direction: column;
    gap: 0.5rem;
}

.preview-items.compact {
    gap: 0.15rem;
}

.preview-item {
    padding: 0.5rem 0.75rem;
    border-radius: 4px;
    display: flex;
    align-items: center;
    gap: 0.5rem;
}

.preview-items.compact .preview-item {
    padding: 0.2rem 0.75rem;
}

.preview-light .preview-item {
    background: #f8f9fa;
}

.preview-dark .preview-item {
    background: #313244;
}

/* ===== Loading ===== */
.loading-spinner {
    display: flex;
    justify-content: center;
    align-items: center;
    height: 200px;
    color: #6c757d;
    font-size: 1.1rem;
}

/* ===== Table ===== */
.settings-section .table {
    margin-top: 0.5rem;
}

